    {
        for(int i=1;i<=n;i++)
        {
            f[i][j][0]=max(f[i][j-1][1],max(f[i][j-1][0],f[i][j-1][2]))+a[i][j];
            if(i>=2)
			{
            	f[i][j][1]=max(f[i-1][j][0],f[i-1][j][1])+a[i][j]; 
			}
        }
        for(int i=n-1;i>=1;i--)
        {
            f[i][j][2]=max(f[i+1][j][0],f[i+1][j][2])+a[i][j];
        }
    }
    cout<<max(f[n][m][0],max(f[n][m][1],f[n][m][2]));
    return 0;
